import{_ as a,o,c as t,a0 as s}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"🔨 如何建立遊戲內箱子商店","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-Create-Shop.md","filePath":"Mc-Create-Shop.md"}'),n={name:"Mc-Create-Shop.md"};function l(r,e,i,c,d,p){return o(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="🔨-如何建立遊戲內箱子商店" tabindex="-1">🔨 如何建立遊戲內箱子商店 <a class="header-anchor" href="#🔨-如何建立遊戲內箱子商店" aria-label="Permalink to &quot;🔨 如何建立遊戲內箱子商店&quot;">​</a></h1><p>只要幾個簡單的步驟，您就可以在您的領地中建立一個自動交易商店。</p><hr><h2 id="📝-1-告示牌書寫格式" tabindex="-1">📝 1. 告示牌書寫格式 <a class="header-anchor" href="#📝-1-告示牌書寫格式" aria-label="Permalink to &quot;📝 1. 告示牌書寫格式&quot;">​</a></h2><p>在箱子（或木桶）的<strong>正面或上方</strong>放置一個告示牌，並依序輸入以下四行內容：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[第一行] [Shop]</span></span>
<span class="line"><span>[第二行] 交易數量 (如: 64)</span></span>
<span class="line"><span>[第三行] 出售價:收購價 (如: B 100:10 S)</span></span>
<span class="line"><span>[第四行] 物品 ID 或手持 [this] 代替</span></span></code></pre></div><h3 id="✍️-參數詳細說明" tabindex="-1">✍️ 參數詳細說明： <a class="header-anchor" href="#✍️-參數詳細說明" aria-label="Permalink to &quot;✍️ 參數詳細說明：&quot;">​</a></h3><ul><li><strong>第一行</strong>：必須輸入 <strong><code>[Shop]</code></strong>（大小寫均可，建立成功後會自動變為黃色加粗 <code>§e§l[Shop]</code>）。</li><li><strong>第二行</strong>：每次交易的物品數量（必須是正整數，例如 <code>1</code> 或 <code>64</code>）。</li><li><strong>第三行</strong>： <ul><li><strong><code>B</code> 代表買入 (Buy)</strong>：買家跟您買的價格。例如 <code>B 100</code>。</li><li><strong><code>S</code> 代表收購 (Sell)</strong>：您向買家回收的價格。例如 <code>S 10</code>。</li><li><strong>雙向設定</strong>：例如 <code>B 100:10 S</code>（代表買家花 $100 買，或把商品以 $10 賣還給您）。</li></ul></li><li><strong>第四行</strong>： <ul><li>手持您要販售的物品，在第四行輸入 <strong><code>[this]</code></strong>（或英文 <code>this</code>）。</li><li>系統會自動辨識您手上的物品，並自動填入正確的物品名稱（如 <code>DIAMOND</code>），避免輸入複雜的 ID！</li></ul></li></ul>`,8)])])}const u=a(n,[["render",l]]);export{g as __pageData,u as default};
